/**
 * Gym equipment location map.
 * x, y are percentages from the TOP-LEFT of the gym floor plan image.
 * Generated by coordinate-picker.html
 */
const GYM_LOCATIONS = {

  /* ── Chest ── */
  "eq_seated_chest_press": { x: 36.21, y: 64.57, label: "Seated Chest Press" },

  /* ── Back ── */
  "eq_lat_pulldown":        { x: 62.15, y: 68.12, label: "Lat Pulldown" },
  "eq_seated_row":          { x: 12.62, y: 57.57, label: "Seated Row" },
  "eq_high_row":            { x: 64.95, y: 67.82, label: "High Row" },
  "eq_assisted_pullup":     { x: 83.64, y: 81.08, label: "Assisted Pull-Up" },

  /* ── Cable ── */
  "eq_cable_station":       { x: 74.53, y: 69.16, label: "Cable Station" },

  /* ── Legs / Glutes ── */
  "eq_seated_leg_press":    { x: 27.80, y: 54.96, label: "Seated Leg Press" },
  "eq_leg_extension":       { x: 35.98, y: 54.37, label: "Leg Extension" },
  "eq_leg_curl":            { x: 35.75, y: 54.07, label: "Leg Curl" },
  "eq_hip_abduction":       { x: 50.23, y: 63.54, label: "Hip Abduction" },
  "eq_hip_adduction":       { x: 50.00, y: 62.65, label: "Hip Adduction" },
  "eq_hip_thrust_machine":  { x: 78.74, y: 40.17, label: "Hip Thrust Machine" },

  /* ── Free Weight ── */
  "eq_free_weight":         { x: 95.79, y: 49.93, label: "Free Weight Area" },

  /* ── Arms ── */
  "eq_biceps_curl_machine": { x: 42.87, y: 54.66, label: "Biceps Curl Machine" },

  /* ── Core ── */
  "eq_ab_crunch_machine":   { x: 94.86, y: 33.37, label: "Ab Crunch Machine" },
};

/**
 * Map exercise -> equipment -> position.
 * Returns { x, y, label } or null.
 *
 * Logic:
 * - exerciseId can be an exercise ID (ex_*) or an equipment ID (eq_*).
 * - If equipment ID: look up GYM_LOCATIONS directly.
 * - If exercise ID: look up exerciseData, find equipment_ids[0], then GYM_LOCATIONS.
 */
function getTraineePosition(exerciseId, exerciseData) {
  if (!exerciseId) return null;

  // If it looks like an equipment ID, use it directly
  if (exerciseId.startsWith("eq_")) {
    return GYM_LOCATIONS[exerciseId] || null;
  }

  // Otherwise treat it as an exercise ID
  const ex = exerciseData.find((e) => e.id === exerciseId);
  if (!ex) return null;

  const eqId = (ex.equipment_ids || [])[0];
  if (!eqId) return null;

  return GYM_LOCATIONS[eqId] || null;
}
